def test_ach_transfer_above_limit_with_stepup_queues_batch(api_client, verified_ach_account, funded_customer, stepup_token):
    payload = {
        "from_account_id": funded_customer["account_id"],
        "to_ach_id": verified_ach_account["ach_id"],
        "amount": "15000.00",
        "currency": "USD"
    }
    headers = {"Authorization": f"Bearer {stepup_token}"}
    resp = api_client.post("/transfers/ach", json=payload, headers=headers)
    assert resp.status_code == 202
    body = resp.json()
    assert body["status"] == "queued"
    assert "transfer_id" in body
